from enum import Enum
from pydantic import BaseModel, validator

class StatusEnum(str, Enum):
    PENDING = 'pending'
    COMPLETED = 'completed'

class Task(BaseModel):
    status: StatusEnum

    @validator('status')
    def validate_status(cls, v):
        if v not in StatusEnum:
            raise ValueError(f'Hallucinated enum: {v}')
        return v

